//! Brute-force the ASET hashes the rainbow table cannot resolve.
//!
//! The unresolved ASET hashes cluster in types whose assets are GENERATED by the
//! build pipeline (terrainmesh: one per c3 cell; lowresterrain: a 20x20 grid;
//! effect/lineregion/path: big flat tables in `resident`/`effects`). Generated
//! assets get generated NAMES, so their names are template-shaped rather than
//! authored — brute-forcing the templates is tractable where a wordlist is not.
//!
//! `pandemic_hash_m2` folds case (the `|0x20` suppression), so only the STRUCTURE
//! of a candidate matters, not its capitalisation — which collapses the search
//! space enormously.
//!
//! Reads the unresolved CSV emitted by `aset_export`, generates candidates, and
//! reports every hit. Confirmed hits are written as a rainbow-table fragment that
//! can be merged into tools/rainbow_table.json.
//!
//! Usage:
//!   cargo run --release -p wad_simulator --bin aset_namehunt -- \
//!       --unresolved docs/data/aset_unresolved.csv --wad game-files/vz.wad \
//!       --out output/aset_namehunt_hits.json

use std::collections::{BTreeMap, HashMap, HashSet};
use std::fs::File;
use std::io::Write;
use std::path::PathBuf;

use clap::Parser;
use mercs2_formats::ffcs::load_ffcs_archive;
use mercs2_formats::hash::pandemic_hash_m2;

#[derive(Parser)]
#[command(about = "Brute-force template names for unresolved ASET hashes")]
struct Cli {
    #[arg(long, default_value = "docs/data/aset_unresolved.csv")]
    unresolved: PathBuf,

    /// WAD to pull PTHS block-path stems from (candidate seeds)
    #[arg(long, default_value = "game-files/vz.wad")]
    wad: PathBuf,

    #[arg(long, default_value = "output/aset_namehunt_hits.json")]
    out: PathBuf,
}

/// Split a CSV line honouring quoted fields.
fn csv_split(line: &str) -> Vec<String> {
    let mut out = Vec::new();
    let mut cur = String::new();
    let mut in_q = false;
    let mut chars = line.chars().peekable();
    while let Some(c) = chars.next() {
        match c {
            '"' if in_q && chars.peek() == Some(&'"') => {
                cur.push('"');
                chars.next();
            }
            '"' => in_q = !in_q,
            ',' if !in_q => out.push(std::mem::take(&mut cur)),
            _ => cur.push(c),
        }
    }
    out.push(cur);
    out
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let cli = Cli::parse();

    // ── targets: unresolved hash -> types ───────────────────────────
    let text = std::fs::read_to_string(&cli.unresolved)?;
    let mut targets: HashMap<u32, String> = HashMap::new();
    for line in text.lines().skip(1) {
        let f = csv_split(line);
        if f.len() < 2 {
            continue;
        }
        let h = u32::from_str_radix(f[0].trim().trim_start_matches("0x"), 16)?;
        targets.insert(h, f[1].clone());
    }
    eprintln!("{} unresolved target hashes", targets.len());

    // ── candidate seeds: PTHS block stems ────────────────────────────
    let mut file = File::open(&cli.wad)?;
    let file_size = file.metadata()?.len();
    let arch = load_ffcs_archive(&mut file, file_size)?;

    let mut stems: HashSet<String> = HashSet::new();
    for p in &arch.paths {
        // "blocks\VZ\c31295_P000_Q3.block" -> "c31295_P000_Q3" and "c31295"
        let base = p
            .rsplit(['\\', '/'])
            .next()
            .unwrap_or(p)
            .trim_end_matches(".block");
        stems.insert(base.to_string());
        if let Some(cut) = base.find("_P0") {
            stems.insert(base[..cut].to_string());
        }
    }
    eprintln!("{} block-path stems seeded from PTHS", stems.len());

    let mut hits: BTreeMap<u32, (String, String)> = BTreeMap::new(); // hash -> (name, why)
    let mut try_name = |name: String, why: &str, hits: &mut BTreeMap<u32, (String, String)>| {
        let h = pandemic_hash_m2(&name);
        if targets.contains_key(&h) && !hits.contains_key(&h) {
            hits.insert(h, (name, why.to_string()));
        }
    };

    // ── family 1: block-stem derived (terrainmesh is 1:1 with its c3 cell) ──
    let affixes: &[(&str, &str)] = &[
        ("", ""),
        ("vz_", ""),
        ("", "_terrain"),
        ("terrain_", ""),
        ("", "_terrainmesh"),
        ("", "_mesh"),
        ("", "_geom"),
        ("", "_lowres"),
        ("lowres_", ""),
        ("", "_lod"),
        ("mesh_", ""),
        ("vz_", "_terrain"),
        ("", "_0"),
        ("", "_1"),
    ];
    for stem in &stems {
        for (pre, suf) in affixes {
            try_name(format!("{pre}{stem}{suf}"), "blockstem", &mut hits);
        }
    }

    // ── family 2: grid coordinates (lowresterrain = 20x20; terrain tiles) ──
    let grid_pats: &[fn(u32, u32) -> String] = &[
        |x, y| format!("terrain_{x}_{y}"),
        |x, y| format!("terrain_{x:02}_{y:02}"),
        |x, y| format!("lowresterrain_{x}_{y}"),
        |x, y| format!("lowresterrain_{x:02}_{y:02}"),
        |x, y| format!("low_res_terrain_{x}_{y}"),
        |x, y| format!("lowres_{x}_{y}"),
        |x, y| format!("lowres_terrain_{x}_{y}"),
        |x, y| format!("vz_terrain_{x}_{y}"),
        |x, y| format!("vz_lowres_{x}_{y}"),
        |x, y| format!("tile_{x}_{y}"),
        |x, y| format!("tile_{x:02}_{y:02}"),
        |x, y| format!("terraintile_{x}_{y}"),
        |x, y| format!("terrain_x{x}_y{y}"),
        |x, y| format!("terrain{x}_{y}"),
        |x, y| format!("t_{x}_{y}"),
        |x, y| format!("terrain_{x}x{y}"),
        |x, y| format!("vz_mar_terrain_{x}_{y}"),
        |x, y| format!("mar_terrain_{x}_{y}"),
    ];
    for x in 0..40u32 {
        for y in 0..40u32 {
            for p in grid_pats {
                try_name(p(x, y), "grid", &mut hits);
            }
        }
    }

    // ── family 3: flat indexed tables (effect / lineregion / path) ──
    let idx_pats: &[fn(u32) -> String] = &[
        |i| format!("effect_{i}"),
        |i| format!("effect{i}"),
        |i| format!("fx_{i}"),
        |i| format!("lineregion_{i}"),
        |i| format!("region_{i}"),
        |i| format!("line_{i}"),
        |i| format!("path_{i}"),
        |i| format!("path{i}"),
        |i| format!("spline_{i}"),
        |i| format!("route_{i}"),
        |i| format!("zone_{i}"),
        |i| format!("terrain_{i}"),
        |i| format!("tile_{i}"),
        |i| format!("lowresterrain_{i}"),
        |i| format!("chatter_{i}"),
    ];
    for i in 0..6000u32 {
        for p in idx_pats {
            try_name(p(i), "index", &mut hits);
        }
    }

    // ── report ──────────────────────────────────────────────────────
    let mut by_why: BTreeMap<String, usize> = BTreeMap::new();
    for (_, (_, why)) in &hits {
        *by_why.entry(why.clone()).or_default() += 1;
    }
    println!("HITS: {} / {} unresolved", hits.len(), targets.len());
    for (why, n) in &by_why {
        println!("  by {why}: {n}");
    }
    for (h, (name, why)) in hits.iter().take(40) {
        let t = targets.get(h).cloned().unwrap_or_default();
        println!("  0x{h:08X}  {name:<40} [{t}] ({why})");
    }

    if let Some(d) = cli.out.parent() {
        std::fs::create_dir_all(d)?;
    }
    let mut map = serde_json::Map::new();
    for (h, (name, _)) in &hits {
        map.insert(
            format!("0x{h:08X}"),
            serde_json::Value::Array(vec![serde_json::Value::String(name.clone())]),
        );
    }
    let root = serde_json::json!({ "pandemic_hash_m2": map });
    let mut f = File::create(&cli.out)?;
    f.write_all(serde_json::to_string_pretty(&root)?.as_bytes())?;
    println!("\nWrote {}", cli.out.display());
    Ok(())
}
